SELECT o.id, o.org_id AS orgId, o.operation_type AS operationType, o.plan_id AS planId, o.start_time AS startTime, o.end_time AS endTime, o.operation_level AS operationLevel, o.affected_households AS affectedHouseholds, o.reason, o.remark, o.status, o.create_time AS createTime, o.create_id AS createId, o.update_time AS updateTime, o.update_id AS updateId, a.detail_address AS detailAddress, t.organization_name AS organizationName FROM gs_cutoff_operation o INNER JOIN gs_cutoff_area_node a ON o.id = a.source_id AND a.source_type = 'OPERATION' LEFT JOIN tbl_organization t ON o.org_id = t.id
o.deleted = 0
AND o.operation_type = #{request.operationType}
AND o.start_time >= #{request.startTime}
AND o.end_time <= #{request.endTime}
